import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { SharedService } from '../../../../../services/shared.service';

@Injectable({
  providedIn: 'root',
})
export class CloseRegisterService {
  apiUrl = this.sharedService.getUrl;
  constructor(private http: HttpClient, public sharedService: SharedService) { }
  getCurrentSessionCollectedBankTransfere(searchText: string, pageNo: number): Observable<any> {
    return this.http.get<any>(
      this.apiUrl +
      `Cashier/GetCurrentSessionCollectedBankTransfere?Search=${searchText}&PageNo=${pageNo - 1}&PageSize=6`,
      this.sharedService.getHeaders()
    );
  }
  actionsOnBankTransfere(transfer: any): Observable<any> {
    return this.http.post<any>(
      this.apiUrl + 'Cashier/ActionsOnBankTransfere',
      transfer,
      this.sharedService.getHeaders()
    );
  }

  editCollectionBankTransfere(transfer: any): Observable<any> {
    return this.http.post<any>(
      this.apiUrl + 'Cashier/EditCollectionBankTransfere',
      transfer,
      this.sharedService.getHeaders()
    );
  }
  reverseActionsOnBankTransfere(transfer: any): Observable<any> {
    return this.http.post<any>(
      this.apiUrl + 'Cashier/ReverseActionsOnBankTransfere',
      transfer,
      this.sharedService.getHeaders()
    );
  }
  // BANK PLEDGES
  getCurrentSessionCollectedBankPledge(searchText: string, pageNo: number): Observable<any> {
    return this.http.get<any>(
      this.apiUrl +
      `Cashier/GetCurrentSessionCollectedBankPledge?Search=${searchText}&PageNo=${pageNo - 1}&PageSize=6`,
      this.sharedService.getHeaders()
    );
  }
  actionsOnBankPledge(pledge: any): Observable<any> {
    return this.http.post<any>(
      this.apiUrl + 'Cashier/ActionsOnBankPledge',
      pledge,
      this.sharedService.getHeaders()
    );
  }

  editCollectionBankPledge(pledge: any): Observable<any> {
    return this.http.post<any>(
      this.apiUrl + 'Cashier/EditCollectionBankPledge',
      pledge,
      this.sharedService.getHeaders()
    );
  }
  reverseActionsOnBankPledge(pledge: any): Observable<any> {
    return this.http.post<any>(
      this.apiUrl + 'Cashier/reverseActionsOnBankPledge',
      pledge,
      this.sharedService.getHeaders()
    );
  }
  GetRegisterClosingData(): Observable<any> {
    return this.http.get<any>(
      this.apiUrl + 'Cashier/GetRegisterClosingData',
      this.sharedService.getHeaders()
    );
  }
  getRegisterClosingDataFinal(): Observable<any> {
    return this.http.get<any>(
      this.apiUrl + 'Cashier/GetRegisterClosingDataFinal',
      this.sharedService.getHeaders()
    );
  }
  CloseRegisterSession(data: any): Observable<any> {
    return this.http.post<any>(
      this.apiUrl + `Cashier/CloseRegisterSession`,
      data,
      this.sharedService.getHeaders()
    );
  }
  CanCloseRegisterSession(data: any): Observable<any> {
    return this.http.post<any>(
      this.apiUrl + `Cashier/CanCloseRegisterSession`,
      data,
      this.sharedService.getHeaders()
    );
  }

  GetCurrentSessionCollectedCheques(
    searchText: string,
    pageNo: number
  ): Observable<any> {
    return this.http.get<any>(
      this.apiUrl +
      `Cashier/GetCurrentSessionCollectedCheques?drawerName=${searchText}&PageNo=${pageNo - 1}&PageSize=6`,
      this.sharedService.getHeaders()
    );
  }
  GetCurrentSessionCollectedCard(
    searchText: string,
    pageNo: number,
    pageSize = 6,
  ): Observable<any> {
    return this.http.get<any>(
      this.apiUrl +
      `Cashier/GetCurrentSessionCollectedCard?PayerName=${searchText}&PageNo=${pageNo - 1}&PageSize=${pageSize}`,
      this.sharedService.getHeaders()
    );
  }

  EditCollectionCheuqe(cheque: any): Observable<any> {
    return this.http.post<any>(
      this.apiUrl + 'Cashier/EditCollectionCheuqe',
      cheque,
      this.sharedService.getHeaders()
    );
  }

  ActionsOnCheques(cheque: any): Observable<any> {
    return this.http.post<any>(
      this.apiUrl + 'Cashier/ActionsOnCheques',
      cheque,
      this.sharedService.getHeaders()
    );
  }
  ReverseActionsOnCheques(cheque: any): Observable<any> {
    return this.http.post<any>(
      this.apiUrl + 'Cashier/ReverseActionsOnCheques',
      cheque,
      this.sharedService.getHeaders()
    );
  }

  EditCollectionByCards(cheque: any): Observable<any> {
    return this.http.post<any>(
      this.apiUrl + 'Cashier/EditCollectionByCards',
      cheque,
      this.sharedService.getHeaders()
    );
  }

  ActionsOnCard(cheque: any): Observable<any> {
    return this.http.post<any>(
      this.apiUrl + 'Cashier/ActionsOnCard',
      cheque,
      this.sharedService.getHeaders()
    );
  }
  actionsOnCardGroup(cheque: any): Observable<any> {
    return this.http.post<any>(
      this.apiUrl + 'Cashier/ActionsOnCardGroup',
      cheque,
      this.sharedService.getHeaders()
    );
  }
  ReverseActionsOnCard(cheque: any): Observable<any> {
    return this.http.post<any>(
      this.apiUrl + 'Cashier/ReverseActionsOnCard',
      cheque,
      this.sharedService.getHeaders()
    );
  }

  getLookupsById(id: any) {
    return this.http.get(
      this.apiUrl + 'Lookups/GetLookups?lookupTypeId=' + id + '&pageNo=0&pageSize=1000',
      this.sharedService.getHeaders()
    );
  }
}
