import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { authGuard } from '../services/auth.guard';
import { DashboardComponent } from './dashboard.component';
import { BankDepositsComponent } from './modules/main-fund/bank-deposits/bank-deposits.component';
import { NoMenuComponent } from './no-menu/no-menu.component';

const routes: Routes = [
  // { path: '', redirectTo: '/branches', pathMatch: 'full' },
  // { path: '', redirectTo: '/opening-register', pathMatch: 'full' },
  {
    path: '',
    component: DashboardComponent,
    canActivate: [authGuard],
    children: [
      {
        path: 'branches',
        loadChildren: () =>
          import('./modules/admin/branches/branches.module').then(
            (m) => m.BranchesModule
          ),
      },
      {
        path: 'main-fund',
        loadChildren: () =>
          import('./modules/main-fund/bank-deposits/bank-deposits.module').then(
            (m) => m.BankDepositsModule
          ),
      },

      {
        path: 'branches',
        loadChildren: () =>
          import('./modules/admin/branches/branches.module').then(
            (m) => m.BranchesModule
          ),
      },
      {
        path: 'registers',
        loadChildren: () =>
          import('./modules/admin/registers/registers.module').then(
            (m) => m.RegistersModule
          ),
      },
      {
        path: 'roles',
        loadChildren: () =>
          import('./modules/admin/roles/roles.module').then(
            (m) => m.RolesModule
          ),
      },
      {
        path: 'users',
        loadChildren: () =>
          import('./modules/admin/users/users.module').then(
            (m) => m.UsersModule
          ),
      },
      {
        path: 'opening-register',
        loadChildren: () =>
          import(
            './modules/cashier/opening-register/opening-register.module'
          ).then((m) => m.OpeningRegisterModule),
      },
      {
        path: 'close-register',
        loadChildren: () =>
          import('./modules/cashier/close-register/close-register.module').then(
            (m) => m.CloseRegisterModule
          ),
      },
      {
        path: 'collect',
        loadChildren: () =>
          import('./modules/cashier/collect/collect.module').then(
            (m) => m.CollectModule
          ),
      },
      {
        path: 'petty-cash',
        loadChildren: () =>
          import('./modules/cashier/petty-cash/petty-cash.module').then(
            (m) => m.PettyCashModule
          ),
      },
      {
        path: 'pettycash-approvals',
        loadChildren: () =>
          import('./modules/cashier/petty-cash-approval/petty-cash-approval.module').then(
            (m) => m.PettyCashApprovalModule
          ),
      },
      {
        path: '',
        loadChildren: () =>
          import('./modules/cashier/petty-cash/dashboard/dashboard.module').then(
            (m) => m.DashboardModule
          ),
      },
      {
        path: 'unsettled-session',
        loadChildren: () =>
          import('./modules/cashier/unsettled-session/unsettled-session.module').then(
            (m) => m.UnsettledSessionModule
          ),
      },
      {
        path: 'return',
        loadChildren: () =>
          import('./modules/cashier/return/return.module').then(
            (m) => m.ReturnModule
          ),
      },
      {
        path: 'treasuryrefundorders',
        loadChildren: () =>
          import('./modules/cashier/return-treasury-fund/return-treasury-fund.module').then(
            (m) => m.ReturnTreasuryFundModule
          ),
      },
      {
        path: 'provide-expenses',
        loadChildren: () =>
          import(
            './modules/main-fund/provide-expenses/provide-expenses.module'
          ).then((m) => m.provideExpensesModule),
      },
      {
        path: 'mainFund-allocation',
        loadChildren: () =>
          import(
            './modules/main-fund/allocation/allocation/allocation.module'
          ).then((m) => m.allocationModule),
      },
      {
        path: 'register-settlements',
        loadChildren: () =>
          import(
            './modules/main-fund/register-settlements/register-settlements.module')
            .then((m) => m.RegisterSettlementsModule)
      },
      {
        path: 'dashboard',
        loadChildren: () =>
          import(
            './modules/main-fund/dashboard/dashboard.module')
            .then((m) => m.DashboardModule)
      },
      {
        path: 'collection-report',
        loadChildren: () =>
          import(
            './modules/collection-report/collection-report.module')
            .then((m) => m.CollectionReportModule)
      },
      {
        path: 'markazia-vouchers',
        loadChildren: () =>
          import('./modules/cashier/markazia-vouchers/markazia-vouchers.module')
            .then(m => m.MarkaziaVouchersModule)

      },
      {
        path: 'mainfund-receipt',
        loadChildren: () =>
          import('./modules/main-fund/receipts/receipts.module').then(
            (m) => m.ReceiptsModule
          ),
      },
      // ========= Treasury  ========================================================
      {
        path: 'allocation',
        loadChildren: () =>
          import('./modules/treasury/allocation/allocation.module').then(
            (m) => m.AllocationModule
          ),
      },
      {
        path: 'transactions',
        loadChildren: () =>
          import('./modules/treasury/transactions/transactions.module').then(
            (m) => m.TransactionsModule
          ),
      },
      {
        path: 'transactions-history',
        loadChildren: () =>
          import(
            './modules/treasury/transactions-history/transactions-history.module'
          ).then((m) => m.TransactionsHistoryModule),
      },
      {
        path: 'pettycash',
        loadChildren: () =>
          import(
            './modules/treasury/petty-cash-treasury/petty-cash-treasury.module'
          ).then((m) => m.PettyCashTreasuryModule),
      },
      {
        path: 'register-bank-deposit',
        loadChildren: () =>
          import(
            './modules/treasury/register-bank-deposit/register-bank-deposit.module'
          ).then((m) => m.RegisterBankDepositModule),
      },
      {
        path: 'profile',
        loadChildren: () =>
          import('./modules/profile/profile.module').then(
            (m) => m.ProfileModule
          ),
      },

      {
        path: 'no-menu',
        component: NoMenuComponent,
      },
    ],
  },
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule],
})
export class DashboardRoutingModule { }
