import { Injectable } from '@angular/core';
import { BehaviorSubject, Subject } from 'rxjs';

@Injectable({
  providedIn: 'root'
})
export class SubjectService {
  isRegisterOpen = new BehaviorSubject(false);
  sessionDetails = new BehaviorSubject({ opened: false });
  isCollectionPaymentDone = new BehaviorSubject(false);
  bankTransferFiles = new BehaviorSubject([]);
  chequeFiles = new BehaviorSubject([]);
  chequeFinanceApprovalFiles = new BehaviorSubject([]);
  bankPledgeFiles = new BehaviorSubject([]);
  orderReturnFilters = new Subject();
  pettyCashTreasuryExpenses = new Subject();
  replenishmentRequestReceived = new BehaviorSubject(false);
  pNCollectionReceiving = new BehaviorSubject(false);
  cashierNote = new Subject();
  collectedOrder = new Subject();
  paymentDoneModalClosed = new Subject();
  updateCustomerInLocalStorage = new Subject();
  constructor() { }
}
