// signalr.service.ts
import { Injectable } from '@angular/core';
import * as signalR from '@microsoft/signalr';
import { timer } from 'rxjs';
import { delayWhen } from 'rxjs/operators';
import { SharedService } from './shared.service';
import { environment } from '../../environments/environment';  // 👈 generic import


@Injectable({
  providedIn: 'root'
})
export class SignalRService {
  private hubConnection: signalR.HubConnection;

  constructor(private sharedService: SharedService) { }

  startConnection() {
    this.hubConnection = new signalR.HubConnectionBuilder()
       .withUrl(`${environment.ChathubUrl}?userId=${this.sharedService.getUserId}`)
      .withAutomaticReconnect()
      .build();
    this.hubConnection.start()
      .then(() => {
        console.log('Connection started')
      })
      .catch(err => {
        //console.log('Error while starting connection: ' + err)
      });
    // Handle connection closed with error
    this.hubConnection.onclose(error => {
      //console.log('Connection closed with error:', error);
      // Manually attempt to reconnect
      this.startConnection();
    });
  }
  addNotificationListener(callback: (data: any) => void) {
    this.hubConnection.on('sendMessage', callback);
  }
  stopConnection() {
    if (this.hubConnection) {
      this.hubConnection.stop().then(() => console.log('Connection stopped'));
    }
  }
}
